(() => {

  const timestamp = Number($('When Executed by Another Workflow').item.json.messages[0].timestamp);
  const baseDate = new Date(timestamp * 1000);

  const localDate = new Date(baseDate.toLocaleString('en-US', {
    timeZone: 'America/El_Salvador'
  }));

  const year = localDate.getFullYear();
  const month = localDate.getMonth();

  const prevMonthDate = new Date(year, month - 1, 1);
  const prevYear = prevMonthDate.getFullYear();
  const prevMonth = prevMonthDate.getMonth();

  const months = [
    'ene','feb','mar','abr','may','jun',
    'jul','ago','sep','oct','nov','dic'
  ];

  const results = [];
  const lastDay = new Date(prevYear, prevMonth + 1, 0).getDate();

  for (let d = 1; d <= lastDay; d++) {
    const date = new Date(prevYear, prevMonth, d);
    const day = date.getDay();

    if (day === 1 || day === 5) {
      results.push(`${d}-${months[prevMonth]}. llantas: baterias:`);
    }
  }

  return results.join('\n');

})()
}}

